export function BrandIcon({ name, size = 18 }) {
  const b = brands[name];
  if (!b) return null;
  return (
    <svg
      className="brand-icon"
      width={size}
      height={size}
      viewBox={b.viewBox}
      aria-hidden="true"
    >
      {b.node}
    </svg>
  );
}
